using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using System.IO;
using T2ACore;
using System.Reflection;
using Microsoft.Extensions.Hosting;

/// <summary>
/// 初始化项目
/// </summary>
public static class StarterCommon
{
    /// <summary>
    /// 添加服务依赖
    /// </summary>
    /// <param name="builder"></param>
    public static void ServiceAdd(this WebApplicationBuilder builder)
    {
        builder.Services.AddSingleton<IDBHelper, DBHelper>();

        if (Config.BaseConfig.CacheType == "Redis")
        {
            builder.Services.AddSingleton<ICache, CacheRedis>();
        }
        else
        {
            builder.Services.AddSingleton<ICache, CacheMemory>();
        }

        builder.Services.AddSingleton<IAuthBusiness, AuthBusiness>();
        builder.Services.AddSingleton<IAssetExecuter, AssetExecuter>();

        builder.Services.AddSingleton<IMenu_Business, Menu_Business>();
        builder.Services.AddSingleton<ILanguage_Business, Language_Business>();
        builder.Services.AddSingleton<IUser_Business, User_Business>();
        builder.Services.AddSingleton<IToken, Token>();
        builder.Services.AddSingleton<ITenant_Business, Tenant_Business>();

        builder.Services.AddSingleton<IFile_record_Business, File_record_Business>();

        if (Config.OssConfig.OssType == "Minio")
        {
            builder.Services.AddSingleton<IFileMange_Business, FileMangeMinio_Business>();
        }
        else if (Config.OssConfig.OssType == "RustFS")
        {
            builder.Services.AddSingleton<IFileMange_Business, FileMangeRustFS_Business>();
        }
        else
        {
            builder.Services.AddSingleton<IFileMange_Business, FileMangeToDisk_Business>();
            Directory.CreateDirectory(Path.Combine(
                Common.CurrentDllPath,
                Config.OssConfig.BucketName));
        }

        //执行现有类和数据库之间的比对
        //builder.Services.AddHostedService<DBDiff_HostedService>();
        builder.Services.AddSingleton<IHostedService>(root =>
        {
            return new DBDiff_HostedService(root, Assembly.GetExecutingAssembly());
        });
    }

}

